const express = require('express');
const { createProxyMiddleware } = require('http-proxy-middleware');
const crypto = require('crypto');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();

// Security headers
app.use(helmet());

// Rate limiting to prevent abuse
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
});
app.use(limiter);

// Disable powered-by header
app.disable('x-powered-by');

// Backend service routing configuration
const SERVICE_ROUTES = {
  '/api/users': { target: process.env.USERS_SERVICE_URL || 'http://localhost:3001' },
  '/api/orders': { target: process.env.ORDERS_SERVICE_URL || 'http://localhost:3002' },
  '/api/products': { target: process.env.PRODUCTS_SERVICE_URL || 'http://localhost:3003' },
};

// Valid API keys stored securely (in production, use a database or secrets manager)
// Keys are stored as SHA-256 hashes to avoid plaintext storage
const VALID_API_KEY_HASHES = new Set(
  (process.env.VALID_API_KEY_HASHES || '').split(',').filter(Boolean)
);

function hashApiKey(key) {
  return crypto.createHash('sha256').update(key).digest('hex');
}

function maskApiKey(key) {
  if (!key || key.length < 8) return '***';
  return key.substring(0, 4) + '****' + key.substring(key.length - 4);
}

function generateRequestId() {
  return crypto.randomUUID();
}

// Request logging middleware - never logs full API keys
function requestLogger(req, res, next) {
  const requestId = generateRequestId();
  req.requestId = requestId;
  const startTime = Date.now();

  // Log request without sensitive data
  const logEntry = {
    requestId,
    timestamp: new Date().toISOString(),
    method: req.method,
    path: req.path,
    ip: req.ip,
    userAgent: req.get('User-Agent'),
    apiKeyPresent: !!req.apiKey,
    apiKeyMasked: req.apiKey ? maskApiKey(req.apiKey) : 'none',
  };

  console.log('[REQUEST]', JSON.stringify(logEntry));

  // Log response on finish
  res.on('finish', () => {
    const duration = Date.now() - startTime;
    console.log('[RESPONSE]', JSON.stringify({
      requestId,
      statusCode: res.statusCode,
      durationMs: duration,
    }));
  });

  next();
}

// API key authentication middleware
// SECURITY: Accept API key ONLY via Authorization header, NOT query parameters
// Query parameters are logged by proxies, appear in browser history, and leak via Referrer headers
function authenticateApiKey(req, res, next) {
  // Extract API key from Authorization header only
  const authHeader = req.get('Authorization');
  let apiKey = null;

  if (authHeader && authHeader.startsWith('Bearer ')) {
    apiKey = authHeader.substring(7).trim();
  }

  // SECURITY: If someone passes api_key as query param, reject and warn
  if (req.query.api_key) {
    console.warn('[SECURITY_WARNING]', JSON.stringify({
      timestamp: new Date().toISOString(),
      message: 'API key passed via query parameter - rejected for security',
      ip: req.ip,
      path: req.path,
    }));
    return res.status(400).json({
      error: 'API keys must not be sent via query parameters. Use the Authorization header: "Bearer <api_key>"',
    });
  }

  if (!apiKey) {
    return res.status(401).json({
      error: 'Missing API key. Provide it via Authorization header: "Bearer <api_key>"',
    });
  }

  // Validate API key using constant-time comparison against stored hashes
  const keyHash = hashApiKey(apiKey);
  let isValid = false;

  for (const validHash of VALID_API_KEY_HASHES) {
    if (validHash.length === keyHash.length) {
      try {
        if (crypto.timingSafeEqual(Buffer.from(keyHash, 'hex'), Buffer.from(validHash, 'hex'))) {
          isValid = true;
          break;
        }
      } catch {
        // Length mismatch or invalid hex - continue
      }
    }
  }

  if (!isValid) {
    console.warn('[AUTH_FAILURE]', JSON.stringify({
      timestamp: new Date().toISOString(),
      ip: req.ip,
      path: req.path,
      apiKeyMasked: maskApiKey(apiKey),
    }));
    return res.status(403).json({ error: 'Invalid API key' });
  }

  // Store for logging (masked) - never store the full key on the request
  req.apiKey = apiKey;
  req.apiKeyHash = keyHash;

  next();
}

// Health check endpoint (no auth required)
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// Apply authentication and logging to all proxied routes
app.use(authenticateApiKey);
app.use(requestLogger);

// Set up proxy routes for each backend service
Object.entries(SERVICE_ROUTES).forEach(([path, config]) => {
  app.use(
    path,
    createProxyMiddleware({
      target: config.target,
      changeOrigin: true,
      // Remove sensitive headers before forwarding
      on: {
        proxyReq: (proxyReq, req) => {
          // Remove the original Authorization header to avoid leaking the gateway API key to backends
          proxyReq.removeHeader('Authorization');

          // Forward an internal authentication header for backend service trust
          // This should be a separate internal secret, not the client's API key
          const internalSecret = process.env.INTERNAL_SERVICE_SECRET;
          if (internalSecret) {
            proxyReq.setHeader('X-Internal-Auth', internalSecret);
          }

          // Forward request ID for tracing
          proxyReq.setHeader('X-Request-Id', req.requestId);

          // Forward a non-sensitive client identifier (hash of API key)
          proxyReq.setHeader('X-Client-Id', req.apiKeyHash);
        },
        proxyRes: (proxyRes, req) => {
          console.log('[PROXY_RESPONSE]', JSON.stringify({
            requestId: req.requestId,
            target: config.target,
            statusCode: proxyRes.statusCode,
          }));
        },
        error: (err, req, res) => {
          console.error('[PROXY_ERROR]', JSON.stringify({
            requestId: req.requestId,
            target: config.target,
            error: err.message,
          }));
          if (!res.headersSent) {
            res.status(502).json({ error: 'Bad gateway', requestId: req.requestId });
          }
        },
      },
      // Timeout settings
      proxyTimeout: 30000,
      timeout: 30000,
    })
  );
});

// 404 handler for unmatched routes
app.use((req, res) => {
  res.status(404).json({ error: 'Route not found', requestId: req.requestId });
});

// Global error handler
app.use((err, req, res, _next) => {
  console.error('[UNHANDLED_ERROR]', JSON.stringify({
    requestId: req.requestId,
    error: err.message,
  }));
  if (!res.headersSent) {
    res.status(500).json({ error: 'Internal server error', requestId: req.requestId });
  }
});

// Start server
const PORT = parseInt(process.env.PORT, 10) || 3000;
const HOST = process.env.HOST || '127.0.0.1';

app.listen(PORT, HOST, () => {
  console.log(`API Gateway running on ${HOST}:${PORT}`);
  console.log('Configured routes:', Object.keys(SERVICE_ROUTES));

  if (VALID_API_KEY_HASHES.size === 0) {
    console.warn('[SECURITY_WARNING] No API key hashes configured. Set VALID_API_KEY_HASHES environment variable.');
    console.warn('Generate a hash with: echo -n "your-api-key" | sha256sum');
  }

  if (!process.env.INTERNAL_SERVICE_SECRET) {
    console.warn('[SECURITY_WARNING] No INTERNAL_SERVICE_SECRET configured for backend authentication.');
  }
});

// Utility script to generate API key hash (run separately)
